settings.liquid:
{% comment %}
  =============================================================
  POP-UP DE PARCELAMENTO - DESIGN "ORELL" (ATUALIZADO)
  - PIX para 7 minutos
  - Novas taxas de juros aplicadas
  - Ajuste de margem (-8px top, 0px bottom) com marcação 🔴
  =============================================================
{% endcomment %}

{% assign current_variant = product.selected_or_first_available_variant %}
{% assign base_price = current_variant.price | default: 0 %}

<style>
  /* Base e Trigger (Botão Link) */
  .orell-installments-section {
    /* 🔴 ALTERE OS ESPAÇAMENTOS AQUI 🔴 */
    margin-top: -26px;    /* 🔴 Espaçamento superior */
    margin-bottom: 0px;  /* 🔴 Espaçamento inferior */

    padding: 0;
    font-family: var(--font-body-family, sans-serif);
  }
  .orell-trigger-btn {
    background: transparent;
    border: none;
    padding: 0;
    text-decoration: underline;
    font-size: 14px;
    color: #1c1c1c;
    cursor: pointer;
    font-family: inherit;
    transition: opacity 0.2s ease;
  }
  .orell-trigger-btn:hover {
    opacity: 0.7;
  }

  /* Overlay (Fundo Escuro) */
  .orell-modal-overlay {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: rgba(0, 0, 0, 0.75);
    z-index: 2147483647; 
    display: flex;
    justify-content: center;
    align-items: center;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.3s ease, visibility 0.3s ease;
  }
  .orell-modal-overlay.is-open {
    opacity: 1;
    visibility: visible;
  }

  /* Container do Pop-up */
  .orell-modal {
    background: #efefef;
    width: 90%;
    max-width: 440px;
    max-height: 85vh;
    border-radius: 0;
    display: flex;
    flex-direction: column;
    box-shadow: 0 10px 30px rgba(0,0,0,0.2);
    transform: translateY(20px);
    transition: transform 0.3s ease;
    font-family: var(--font-body-family, sans-serif);
  }
  .orell-modal-overlay.is-open .orell-modal {
    transform: translateY(0);
  }

  /* Cabeçalho */
  .orell-modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 20px 24px;
    border-bottom: 1px solid rgba(28, 28, 28, 0.1);
  }
  .orell-modal-title {
    margin: 0;
    font-size: 16px;
    font-weight: 600;
    font-family: var(--font-heading-family, sans-serif);
    text-transform: uppercase;
    color: #1c1c1c;
    letter-spacing: 0.05em;
  }
  .orell-close-btn {
    background: none;
    border: none;
    font-size: 26px;
    line-height: 1;
    cursor: pointer;
    color: #1c1c1c;
    padding: 0;
  }

  /* Corpo */
  .orell-modal-body {
    padding: 20px 24px;
    overflow-y: auto;
  }

  /* Acordeões */
  .orell-accordion {
    border: 1px solid rgba(28, 28, 28, 0.15);
    border-radius: 0;
    margin-bottom: 16px;
    overflow: hidden;
    background: transparent;
  }
  .orell-accordion-header {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 16px;
    background: transparent;
    border: none;
    cursor: pointer;
  }
  .orell-accordion-title {
    display: flex;
    align-items: center;
    font-size: 14px;
    font-weight: 600;
    font-family: var(--font-heading-family, sans-serif);
    text-transform: uppercase;
    color: #1c1c1c;
    letter-spacing: 0.03em;
  }

  /* Badge Circular */
  .orell-badge {
    display: flex;
    justify-content: center;
    align-items: center;
    width: 26px;
    height: 26px;
    border-radius: 50%;
    background-color: #1c1c1c;
    margin-right: 12px;
    font-size: 13px;
    font-weight: 700;
    color: #efefef;
  }

  /* Seta Giratória */
  .orell-chevron {
    width: 10px;
    height: 10px;
    border-right: 2px solid #1c1c1c;
    border-bottom: 2px solid #1c1c1c;
    transform: rotate(45deg);
    transition: transform 0.3s ease;
    margin-top: -4px;
  }
  .orell-accordion.is-active .orell-chevron {
    transform: rotate(-135deg);
    margin-top: 4px;
  }

  .orell-accordion-content {
    display: none;
    padding: 0 16px 20px;
  }
  .orell-accordion.is-active .orell-accordion-content {
    display: block;
  }

  /* Tabela de Parcelamento */
  .orell-table-head {
    display: flex;
    justify-content: space-between;
    font-weight: 700;
    font-size: 14px;
    color: #1c1c1c;
    padding: 8px 0 12px 0;
    border-bottom: 2px solid rgba(28, 28, 28, 0.15);
    margin-bottom: 4px;
  }
  .orell-table-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-size: 14px;
    color: #1c1c1c;
    padding: 10px 0;
    border-bottom: 1px solid rgba(28, 28, 28, 0.08);
  }
  .orell-table-row:last-child {
    border-bottom: none;
  }

  /* Labels (Com juros / Sem Juros) */
  .orell-interest-label {
    font-size: 11px;
    margin-left: 6px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.02em;
  }
  .orell-label-free {
    color: #1c1c1c; /* Preto destaque para sem juros */
  }
  .orell-label-fee {
    color: #888888; /* Cinza para não chamar tanta atenção ao juros */
    font-weight: 500;
  }

  .orell-secure-text {
    font-size: 12px;
    color: rgba(28, 28, 28, 0.6);
    text-align: center;
    margin-top: 20px;
    line-height: 1.4;
  }

  /* Conteúdo PIX */
  .orell-pix-content { padding-top: 8px; }
  .orell-pix-price {
    font-size: 24px;
    font-weight: 600;
    color: #1c1c1c;
    margin: 0 0 16px 0;
    font-family: var(--font-heading-family, sans-serif);
  }
  .orell-pix-list {
    padding-left: 18px;
    margin: 0;
    font-size: 14px;
    color: #1c1c1c;
    line-height: 1.6;
  }
  .orell-pix-list li { margin-bottom: 8px; }
</style>

<!-- Gatilho -->
<div class="orell-installments-section">
  <button id="orellPaymentTrigger" class="orell-trigger-btn" type="button">
    ou <span id="orellPriceTrigger">R$ --</span> em 12x com juros
  </button>
</div>

<!-- Modal -->
<div id="orellPaymentModal" class="orell-modal-overlay" aria-hidden="true">
  <div class="orell-modal">

    <div class="orell-modal-header">
      <h2 class="orell-modal-title">Formas de Pagamento</h2>
      <button id="orellModalClose" class="orell-close-btn">&times;</button>
    </div>

    <div class="orell-modal-body">

      <!-- Cartão de Crédito -->
      <div class="orell-accordion is-active">
        <button class="orell-accordion-header" type="button">
          <div class="orell-accordion-title">
            <span class="orell-badge">1</span> Cartão de Crédito
          </div>
          <span class="orell-chevron"></span>
        </button>
        <div class="orell-accordion-content">
          <div class="orell-table-head">
            <span>Parcela</span>
            <span>Total</span>
          </div>
          <div id="orellCreditInstallments">
            <!-- Injetado via Javascript -->
          </div>
          <p class="orell-secure-text">Pagamento 100% protegido por nossa tecnologia de criptografia avançada.</p>
        </div>
      </div>

      <!-- PIX -->
      <div class="orell-accordion">
        <button class="orell-accordion-header" type="button">
          <div class="orell-accordion-title">
            <span class="orell-badge">2</span> PIX À VISTA
          </div>
          <span class="orell-chevron"></span>
        </button>
        <div class="orell-accordion-content">
          <div class="orell-pix-content">
            <h3 id="orellPixPrice" class="orell-pix-price">R$ --</h3>
            <ol class="orell-pix-list">
              <!-- Tempo do PIX atualizado para 7 minutos -->
              <li>O código Pix ficará disponível por 7 minutos após finalizar a compra.</li>
              <li>A aprovação é imediata! Seu pedido é separado e enviado rapidamente.</li>
            </ol>
          </div>
        </div>
      </div>

    </div>
  </div>
</div>

<script>
document.addEventListener('DOMContentLoaded', function() {
  const basePriceCents = {{ base_price }};
  if (basePriceCents <= 0) return;

  // Novas taxas (1x, 2x e 3x sem juros; restantes conforme lista atualizada)
  const rates =[
    1.0,      // 1x (0%)
    1.0,      // 2x (0%)
    1.0,      // 3x (0%)
    1.1136,   // 4x (11,36%)
    1.1431,   // 5x (14,31%)
    1.1432,   // 6x (14,32%)
    1.1672,   // 7x (16,72%)
    1.1673,   // 8x (16,73%)
    1.1969,   // 9x (19,69%)
    1.2065,   // 10x (20,65%)
    1.2066,   // 11x (20,66%)
    1.2211    // 12x (22,11%)
  ];

  const formatMoney = (cents) => {
    return (cents / 100).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  // Atualizar ativador (12x)
  const total12x = Math.round(basePriceCents * rates[11]);
  const parcel12x = Math.round(total12x / 12);
  const triggerSpan = document.getElementById('orellPriceTrigger');
  if(triggerSpan) triggerSpan.innerText = formatMoney(parcel12x);

  // Gerar a tabela com as tags de juros
  const tableBody = document.getElementById('orellCreditInstallments');
  if(tableBody) {
    let rowsHTML = '';
    for(let i = 0; i < rates.length; i++) {
      const installments = i + 1;
      const totalAmount = Math.round(basePriceCents * rates[i]);
      const parcelAmount = Math.round(totalAmount / installments);

      // Lógica das tags de texto (até 3x sem juros)
      const isFree = installments <= 3;
      const interestText = isFree ? 'sem juros' : 'com juros';
      const labelClass = isFree ? 'orell-label-free' : 'orell-label-fee';

      rowsHTML += `
        <div class="orell-table-row">
          <span>
            ${installments}x ${formatMoney(parcelAmount)} 
            <span class="orell-interest-label ${labelClass}">${interestText}</span>
          </span>
          <span>${formatMoney(totalAmount)}</span>
        </div>
      `;
    }
    tableBody.innerHTML = rowsHTML;
  }

  // Atualizar PIX
  const pixPriceEl = document.getElementById('orellPixPrice');
  if(pixPriceEl) pixPriceEl.innerText = formatMoney(basePriceCents);

  // Funcionalidade Pop-up
  const triggerBtn = document.getElementById('orellPaymentTrigger');
  const closeBtn = document.getElementById('orellModalClose');
  const modalOverlay = document.getElementById('orellPaymentModal');

  if(triggerBtn && closeBtn && modalOverlay) {
    document.body.appendChild(modalOverlay);

    const openModal = (e) => {
      e.preventDefault();
      modalOverlay.classList.add('is-open');
      document.body.style.overflow = 'hidden'; 
    };
    const closeModal = () => {
      modalOverlay.classList.remove('is-open');
      document.body.style.overflow = ''; 
    };

    triggerBtn.addEventListener('click', openModal);
    closeBtn.addEventListener('click', closeModal);
    modalOverlay.addEventListener('click', (e) => {
      if(e.target === modalOverlay) closeModal();
    });
  }

  // Funcionalidade Abas
  const headers = document.querySelectorAll('.orell-accordion-header');
  headers.forEach(header => {
    header.addEventListener('click', function() {
      const parent = this.parentElement;
      const isActive = parent.classList.contains('is-active');

      document.querySelectorAll('.orell-accordion').forEach(acc => {
        acc.classList.remove('is-active');
      });

      if(!isActive) {
        parent.classList.add('is-active');
      }
    });
  });
});
</script>
